

export const preview_data = (number, setPreviewData, setPopout) => {
    fetch(`https://data.gibdd-proverka.ru/check/auto/prerequest/?vin_grz=${number}&key=Yu8fJszHk4p73pvc`)
    .then(function(response) {
        return response.json();
    })
    .then(function(data) {
        if(data) {
            setPreviewData(data)
            setPopout(null)
        }
    })
}

