import React, {useState} from 'react';
import PropTypes from 'prop-types';
import Panel from '@vkontakte/vkui/dist/components/Panel/Panel';
import PanelHeader from '@vkontakte/vkui/dist/components/PanelHeader/PanelHeader';
import Button from '@vkontakte/vkui/dist/components/Button/Button';
import Group from '@vkontakte/vkui/dist/components/Group/Group';
import Cell from '@vkontakte/vkui/dist/components/Cell/Cell';
import Div from '@vkontakte/vkui/dist/components/Div/Div';
import Avatar from '@vkontakte/vkui/dist/components/Avatar/Avatar';
import FormLayout from "@vkontakte/vkui/dist/es6/components/FormLayout/FormLayout";
import Input from "@vkontakte/vkui/dist/es6/components/Input/Input";
import FormStatus from "@vkontakte/vkui/dist/es6/components/FormStatus/FormStatus";


const Home = (props) => {
	const { id, go, fetchedUser, setPopout, previewData, number, changeNumber, isValidNumber, getPreviewData, getGibddHistory } = props

	const hashtag = <span className="bl_color">#</span>

	return 	<Panel id={id}>
		<PanelHeader>ГИБДД проверка</PanelHeader>
		{fetchedUser &&
		<Group>
			<Cell
				before={fetchedUser.photo_200 ? <Avatar src={fetchedUser.photo_200}/> : null}
				description={fetchedUser.city && fetchedUser.city.title ? fetchedUser.city.title : ''}
			>
				{`${fetchedUser.first_name} ${fetchedUser.last_name}`}
			</Cell>
		</Group>}

		<Group>
			<Div>
				<h2>Узнай её прошлое,</h2>
				<h2>прежде чем взять</h2>
				<h5>Проверка истории авто по VIN или госномеру за 100₽</h5>
			</Div>
				<FormLayout >
					<Input status={isValidNumber? "default" : "error"} type="text" value={number} onChange={changeNumber} alignment="center" placeholder='VIN или госномер' />
					{!isValidNumber && <FormStatus state="error">
						Некорректный VIN или госномер
					</FormStatus>}
				</FormLayout>
			<Div>
				<Button size="xl" disabled={!isValidNumber || !number} onClick={getPreviewData} >
					Проверить авто
				</Button>
			</Div>
		</Group>
		{previewData && <Group>
			<Div className='textCenter'>
				<h2>
					{previewData.model}, {previewData.year}
				</h2>
				<p>
					{hashtag}{"VIN:" + previewData.body_number + "  "}
					{hashtag}{"госномер:" + previewData.plate + "  "}
					{hashtag}{previewData.capacity + " куб. см" + "  "}
					{hashtag}{previewData.power + "  л.с." + "  "}
				</p>
				<img src={previewData.image} alt='photo' className='photo'/>
			</Div>
			<Div className='textCenter'>
				<h3>В полном отчёте за 100₽ 77₽ доступно:</h3>
				<p>
					{hashtag}пробег {hashtag}регистрации {hashtag}ДТП {hashtag}ограничения {hashtag}розыск {hashtag}данные о залогах {hashtag}диагностическая карта {hashtag}ОСАГО {hashtag}штрафы {hashtag}фотографии {hashtag}объявления о продаже {hashtag}профили на drive2.ru {hashtag}проверка на работу в такси #характеристики авто
				</p>
			</Div>

			<Div>
				<Button size="xl" disabled={!isValidNumber || !number} onClick={getGibddHistory} >
					Купить полный отчет
				</Button>
			</Div>
		</Group>}
	</Panel>

};

Home.propTypes = {
	id: PropTypes.string.isRequired,
	go: PropTypes.func.isRequired,
	fetchedUser: PropTypes.shape({
		photo_200: PropTypes.string,
		first_name: PropTypes.string,
		last_name: PropTypes.string,
		city: PropTypes.shape({
			title: PropTypes.string,
		}),
	}),
};

export default Home;
